import { Container } from '@adobe-commerce/elsie/lib';
import { useCallback, useEffect, useMemo, useState } from 'preact/hooks';
import { AddressValidation as AddressValidationComponent } from '@/checkout/components';
import { Cart, AddressInput, NegotiableQuote } from '@/checkout/data/models';
import { getLatestCheckoutUpdate } from '@/checkout/lib';
import { events } from '@adobe-commerce/event-bus';
import { transformAddressToCartAddressInput } from '@/checkout/data/transforms/transform-cart-address';

export interface AddressValidationProps {
  suggestedAddress: Partial<AddressInput> | null;
  handleSelectedAddress?: (payload: {
    selection: 'suggested' | 'original';
    address: AddressInput | null | undefined;
  }) => void;
}

export const AddressValidation: Container<AddressValidationProps> = ({
  suggestedAddress,
  handleSelectedAddress,
}) => {
  const [selection, setSelection] = useState<'suggested' | 'original' | null>(
    null
  );
  const [currentAddress, setCurrentAddress] = useState<
    AddressInput | null | undefined
  >(undefined);
  const [busy, setBusy] = useState(false);

  const mergedSuggestedAddress = useMemo<AddressInput | null>(() => {
    if (!suggestedAddress || !currentAddress) return null;
    return { ...currentAddress, regionId: undefined, ...suggestedAddress };
  }, [currentAddress, suggestedAddress]);

  const handleCheckoutData = useCallback(
    (data: Cart | NegotiableQuote | null) => {
      const addr = (data as Cart | null)?.shippingAddresses?.[0];
      const input = transformAddressToCartAddressInput(addr);
      setCurrentAddress(input);
    },
    []
  );

  useEffect(() => {
    const onCheckoutInitialized = events.on(
      'checkout/initialized',
      (data: Cart | NegotiableQuote | null) => {
        handleCheckoutData(data);
      },
      { eager: true }
    );

    return () => {
      onCheckoutInitialized?.off();
    };
  }, [handleCheckoutData]);

  useEffect(() => {
    const pastUpdate = getLatestCheckoutUpdate();
    if (pastUpdate) {
      handleCheckoutData(pastUpdate);
    }

    const onCheckoutUpdated = events.on(
      'checkout/updated',
      (data: Cart | NegotiableQuote | null) => {
        handleCheckoutData(data);
      },
      { eager: false }
    );

    return () => {
      onCheckoutUpdated?.off();
    };
  }, [handleCheckoutData]);

  const onSelectionChange = useCallback(
    async (sel: 'suggested' | 'original') => {
      setSelection(sel);
      const chosen =
        sel === 'suggested' ? mergedSuggestedAddress : currentAddress;
      setBusy(true);
      try {
        await handleSelectedAddress?.({ selection: sel, address: chosen });
      } finally {
        setBusy(false);
      }
    },
    [mergedSuggestedAddress, currentAddress, handleSelectedAddress]
  );

  return (
    <AddressValidationComponent
      busy={busy}
      currentAddress={currentAddress}
      selection={selection}
      suggestedAddress={mergedSuggestedAddress}
      onSelectionChange={onSelectionChange}
    />
  );
};
